import React, { useState, useRef, useCallback } from "react";

const LAUGH_AUDIO: string = "data:audio/mp3;base64,";

function decodeAudio(ctx: AudioContext, uri: string): Promise<AudioBuffer> {
  const bin: string = atob(uri.split(",")[1]);
  const buf: ArrayBuffer = new ArrayBuffer(bin.length);
  const view: Uint8Array = new Uint8Array(buf);
  for (let i = 0; i < bin.length; i++) view[i] = bin.charCodeAt(i);
  return ctx.decodeAudioData(buf);
}

const LaughTrack: React.FC = () => {
  const ctxRef = useRef<AudioContext | null>(null);
  const bufRef = useRef<AudioBuffer | null>(null);
  const [ready, setReady] = useState<boolean>(false);
  const [pressed, setPressed] = useState<boolean>(false);

  const init = useCallback(async (): Promise<void> => {
    if (ctxRef.current) return;
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    ctxRef.current = ctx;
    bufRef.current = await decodeAudio(ctx, LAUGH_AUDIO);
    setReady(true);
  }, []);

  const play = useCallback(async (): Promise<void> => {
    if (!ready) {
      await init();
      setTimeout(() => {
        const ctx = ctxRef.current;
        if (ctx && bufRef.current) {
          if (ctx.state === "suspended") ctx.resume();
          const src: AudioBufferSourceNode = ctx.createBufferSource();
          src.buffer = bufRef.current;
          src.connect(ctx.destination);
          src.start();
        }
      }, 50);
      return;
    }
    const ctx = ctxRef.current!;
    if (ctx.state === "suspended") ctx.resume();
    const src: AudioBufferSourceNode = ctx.createBufferSource();
    src.buffer = bufRef.current;
    src.connect(ctx.destination);
    src.start();
  }, [ready, init]);

  return (
    <div>
      <button
        onPointerDown={() => { setPressed(true); play(); }}
        onPointerUp={() => setPressed(false)}
        onPointerLeave={() => setPressed(false)}
        style={{
          width: "min(80vw, 80vh)",
          height: "min(80vw, 80vh)",
          borderRadius: "50%",
          border: "none",
          cursor: "pointer",
          background: pressed
            ? "radial-gradient(circle at 45% 42%, #cc2222, #881111)"
            : "radial-gradient(circle at 45% 42%, #ee3333, #aa1515)",
          boxShadow: pressed
            ? "inset 0 4px 20px rgba(0,0,0,0.4)"
            : "0 8px 30px rgba(0,0,0,0.5), 0 0 0 6px #222, 0 0 0 10px #333",
          color: pressed ? "#ffffff88" : "#ffffffcc",
          fontSize: "clamp(16px, 4vw, 28px)",
          fontFamily: "system-ui, sans-serif",
          fontWeight: 500,
          letterSpacing: 4,
          textTransform: "lowercase" as const,
          transform: pressed ? "scale(0.97)" : "scale(1)",
          transition: "transform 0.1s, box-shadow 0.1s",
          WebkitTapHighlightColor: "transparent",
          userSelect: "none" as const,
        }}
      >
        press
      </button>
    </div>
  );
};

export default LaughTrack;
